#include <iostream>

int main() {
  int a = 10;
  int b = 3;
  std::cout << "Toplama: " << a + b << std::endl;
  std::cout << "Çıxma: " << a - b << std::endl;
  std::cout << "Vurma: " << a * b << std::endl;
  std::cout << "Bölmə: " << a / b << std::endl;
  std::cout << "Modul: " << a % b << std::endl;
  a++;
  std::cout << "Artırma: " << a << std::endl;
  return 0;
}
// Output:
// Toplama: 13
// Çıxma: 7
// Vurma: 30
// Bölmə: 3
// Modul: 1
// Artırma: 11

#include <iostream>

int main() {
  int x = 5;
  int y = 10;
  std::cout << "x == y: " << (x == y) << std::endl;
  std::cout << "x != y: " << (x != y) << std::endl;
  std::cout << "x > y: " << (x > y) << std::endl;
  std::cout << "x <= y: " << (x <= y) << std::endl;
  return 0;
}
// Output:
// x == y: 0
// x != y: 1
// x > y: 0
// x <= y: 1

#include <iostream>

int main() {
  bool isSunny = true;
  bool isWarm = false;
  std::cout << "Sunny and Warm: " << (isSunny && isWarm) << std::endl;
  std::cout << "Sunny or Warm: " << (isSunny || isWarm) << std::endl;
  std::cout << "Not Sunny: " << (!isSunny) << std::endl;
  return 0;
}
// Output:
// Sunny and Warm: 0
// Sunny or Warm: 1
// Not Sunny: 0

