int main() {
  int price = 100;
  double discount = 0.2;
  double finalPrice = price * (1 - discount);
  std::cout << "Final Price: " << finalPrice << std::endl;
  bool isExpensive = finalPrice > 50;
  std::cout << "Is Expensive: " << isExpensive << std::endl;
  return 0;
}
// Output:
// Final Price: 80
// Is Expensive: 1

